    /// <summary>
    /// Utility class for redacting sensitive information before logging
    /// </summary>
    public static class LogRedactor
    {
        private static readonly HashSet<string> SensitiveHeaders = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "Authorization",
            "Cookie",
            "Set-Cookie",
            "X-API-Key",
            "X-Auth-Token",
            "Proxy-Authorization",
            "X-CSRF-Token",
            "X-Forwarded-For"
        };

        private static readonly string[] SensitiveBodyFields = new[]
        {
            "password", "passwd", "secret", "token", "apiKey", "api_key",
            "creditCard", "credit_card", "cardNumber", "card_number",
            "cvv", "ssn", "socialSecurity", "social_security",
            "dateOfBirth", "date_of_birth", "dob",
            "bankAccount", "bank_account", "routingNumber", "routing_number",
            "pin", "securityAnswer", "security_answer"
        };

        public static string RedactHeaderValue(string headerName, string headerValue)
        {
            if (SensitiveHeaders.Contains(headerName))
            {
                if (headerName.Equals("Authorization", StringComparison.OrdinalIgnoreCase) && headerValue != null)
                {
                    var parts = headerValue.Split(' ');
                    if (parts.Length >= 2)
                    {
                        return $"{parts[0]} [REDACTED-{parts[1].Length}chars]";
                    }
                }
                return "[REDACTED]";
            }
            return headerValue;
        }

        public static string RedactRequestBody(string body, string contentType)
        {
            if (string.IsNullOrEmpty(body))
                return "[empty]";

            if (contentType?.Contains("application/json", StringComparison.OrdinalIgnoreCase) == true)
            {
                try
                {
                    var obj = JsonConvert.DeserializeObject<Dictionary<string, object>>(body);
                    if (obj != null)
                    {
                        var redacted = new Dictionary<string, object>();
                        foreach (var kvp in obj)
                        {
                            if (SensitiveBodyFields.Any(f => kvp.Key.Contains(f, StringComparison.OrdinalIgnoreCase)))
                            {
                                redacted[kvp.Key] = "[REDACTED]";
                            }
                            else
                            {
                                redacted[kvp.Key] = kvp.Value;
                            }
                        }
                        return JsonConvert.SerializeObject(redacted);
                    }
                }
                catch
                {
                    return $"[non-parseable JSON, {body.Length} bytes]";
                }
            }

            // For non-JSON content, log only metadata
            return $"[{contentType ?? "unknown"} content, {body.Length} bytes]";
        }

        public static string RedactConnectionString(string connectionString)
        {
            if (string.IsNullOrEmpty(connectionString))
                return "[empty]";

            var builder = new SqlConnectionStringBuilder(connectionString);
            if (!string.IsNullOrEmpty(builder.Password))
                builder.Password = "[REDACTED]";
            if (!string.IsNullOrEmpty(builder.UserID))
                builder.UserID = MaskValue(builder.UserID);
            return builder.ToString();
        }

        public static string RedactParameterValue(string paramName, object value)
        {
            if (SensitiveBodyFields.Any(f => paramName.Contains(f, StringComparison.OrdinalIgnoreCase)))
            {
                return "[REDACTED]";
            }
            return value?.ToString() ?? "null";
        }

        public static string MaskEmail(string email)
        {
            if (string.IsNullOrEmpty(email) || !email.Contains('@'))
                return "[REDACTED-email]";

            var parts = email.Split('@');
            var localPart = parts[0];
            var masked = localPart.Length > 2
                ? $"{localPart[0]}***{localPart[^1]}"
                : "***";
            return $"{masked}@{parts[1]}";
        }

        public static string MaskValue(string value)
        {
            if (string.IsNullOrEmpty(value))
                return "[empty]";
            if (value.Length <= 4)
                return "****";
            return $"{value[..2]}***{value[^2..]}";
        }

        public static string HashForCorrelation(string value)
        {
            if (string.IsNullOrEmpty(value))
                return "[empty]";

            using var sha = System.Security.Cryptography.SHA256.Create();
            var hash = sha.ComputeHash(System.Text.Encoding.UTF8.GetBytes(value));
            return $"hash:{Convert.ToBase64String(hash)[..12]}";
        }
    }

    /// <summary>
