    public class DiagnosticContext
    {
        public string CorrelationId { get; set; }
        public string RequestId { get; set; }
        public DateTime Timestamp { get; set; }
        public string Operation { get; set; }
        public string UserId { get; set; } // Should be an opaque identifier, not PII
    }

    /// <summary>
    /// SECURE diagnostic Azure Function with proper log hygiene
    /// </summary>
    public static class SecureDiagnosticFunction
    {
        [FunctionName("SecureDiagnostic")]
        public static async Task<IActionResult> Run(
            [HttpTrigger(AuthorizationLevel.Function, "get", "post", "put", "delete", Route = "api/{*path}")] HttpRequest req,
            string path,
            ILogger log)
        {
            var diagnosticContext = new DiagnosticContext
            {
                CorrelationId = req.Headers["X-Correlation-ID"].FirstOrDefault() ?? Guid.NewGuid().ToString("N"),
                RequestId = Guid.NewGuid().ToString("N"),
                Timestamp = DateTime.UtcNow,
                Operation = $"{req.Method} /{path}"
            };

            using (log.BeginScope(new Dictionary<string, object>
            {
                ["CorrelationId"] = diagnosticContext.CorrelationId,
                ["RequestId"] = diagnosticContext.RequestId
            }))
            {
                try
                {
                    // Log request metadata (safe information only)
                    LogRequestMetadata(req, path, diagnosticContext, log);

                    // Log safe headers (with sensitive values redacted)
                    LogSafeHeaders(req, log);

                    // Read and log redacted body
                    req.EnableBuffering();
                    string requestBody;
                    using (var reader = new StreamReader(req.Body, leaveOpen: true))
                    {
                        requestBody = await reader.ReadToEndAsync();
                        req.Body.Position = 0;
                    }

                    var contentType = req.ContentType;
                    var redactedBody = LogRedactor.RedactRequestBody(requestBody, contentType);
                    log.LogInformation(
                        "Request body (redacted): {RedactedBody}",
                        redactedBody);

                    // Extract user context safely
                    var userContext = ExtractSafeUserContext(req, log);
                    diagnosticContext.UserId = userContext.OpaqueUserId;

                    // Simulate business logic with database call
                    var result = await ProcessRequestAsync(path, requestBody, diagnosticContext, log);

                    log.LogInformation(
                        "Request completed successfully. CorrelationId: {CorrelationId}, Duration: {DurationMs}ms",
                        diagnosticContext.CorrelationId,
                        (DateTime.UtcNow - diagnosticContext.Timestamp).TotalMilliseconds);

                    return new OkObjectResult(new
                    {
                        correlationId = diagnosticContext.CorrelationId,
                        status = "success",
                        data = result
                    });
                }
                catch (SqlException ex)
                {
                    // Log database errors with safe details
                    log.LogError(ex,
                        "Database error processing request. " +
                        "CorrelationId: {CorrelationId}, " +
                        "ErrorNumber: {ErrorNumber}, " +
                        "ErrorState: {ErrorState}, " +
                        "ErrorClass: {ErrorClass}, " +
                        "Procedure: {Procedure}, " +
                        "LineNumber: {LineNumber}, " +
                        "Operation: {Operation}",
                        diagnosticContext.CorrelationId,
                        ex.Number,
                        ex.State,
                        ex.Class,
                        ex.Procedure,
                        ex.LineNumber,
                        diagnosticContext.Operation);

                    return new StatusCodeResult(StatusCodes.Status503ServiceUnavailable);
                }
                catch (UnauthorizedAccessException ex)
                {
                    // Don't log details about auth failures that could aid attackers
                    log.LogWarning(
                        "Authorization failed. CorrelationId: {CorrelationId}, Operation: {Operation}, UserHash: {UserHash}",
                        diagnosticContext.CorrelationId,
                        diagnosticContext.Operation,
                        diagnosticContext.UserId ?? "anonymous");

                    return new UnauthorizedResult();
                }
                catch (Exception ex)
                {
                    // Log exception with full stack trace but no sensitive request data
                    log.LogError(ex,
                        "Unhandled exception processing request. " +
                        "CorrelationId: {CorrelationId}, " +
                        "RequestId: {RequestId}, " +
                        "Operation: {Operation}, " +
                        "ExceptionType: {ExceptionType}, " +
                        "ExceptionMessage: {ExceptionMessage}",
                        diagnosticContext.CorrelationId,
                        diagnosticContext.RequestId,
                        diagnosticContext.Operation,
                        ex.GetType().FullName,
                        ex.Message);

                    // Log inner exceptions
                    var innerEx = ex.InnerException;
                    int depth = 0;
                    while (innerEx != null && depth < 5)
                    {
                        log.LogError(
                            "Inner exception (depth {Depth}): Type={ExceptionType}, Message={Message}",
                            depth,
                            innerEx.GetType().FullName,
                            innerEx.Message);
                        innerEx = innerEx.InnerException;
                        depth++;
                    }

                    return new StatusCodeResult(StatusCodes.Status500InternalServerError);
                }
            }
        }

        private static void LogRequestMetadata(HttpRequest req, string path, DiagnosticContext ctx, ILogger log)
        {
            log.LogInformation(
                "Incoming request. " +
                "Method: {Method}, " +
                "Path: {Path}, " +
                "QueryString: {QueryString}, " +
                "ContentType: {ContentType}, " +
                "ContentLength: {ContentLength}, " +
                "Scheme: {Scheme}, " +
                "Host: {Host}, " +
                "CorrelationId: {CorrelationId}",
                req.Method,
                path,
                req.QueryString.HasValue ? req.QueryString.Value : "[none]",
                req.ContentType ?? "[none]",
                req.ContentLength ?? 0,
                req.Scheme,
                req.Host.Value,
                ctx.CorrelationId);
        }

        private static void LogSafeHeaders(HttpRequest req, ILogger log)
        {
            var safeHeaders = new Dictionary<string, string>();
            foreach (var header in req.Headers)
            {
                safeHeaders[header.Key] = LogRedactor.RedactHeaderValue(header.Key, header.Value.ToString());
            }

            log.LogDebug("Request headers (redacted): {Headers}",
                JsonConvert.SerializeObject(safeHeaders));
        }

        private static (string OpaqueUserId, string[] Roles) ExtractSafeUserContext(HttpRequest req, ILogger log)
        {
            var claimsPrincipal = req.HttpContext.User;

            if (claimsPrincipal?.Identity?.IsAuthenticated == true)
            {
                // Use a hash or opaque ID, never log the actual user identifier directly
                var subjectClaim = claimsPrincipal.FindFirst(ClaimTypes.NameIdentifier)?.Value;
                var opaqueUserId = subjectClaim != null
                    ? LogRedactor.HashForCorrelation(subjectClaim)
                    : "authenticated-unknown";

                var roles = claimsPrincipal.Claims
                    .Where(c => c.Type == ClaimTypes.Role)
                    .Select(c => c.Value)
                    .ToArray();

                log.LogInformation(
                    "Authenticated user. UserHash: {UserHash}, Roles: {Roles}, AuthType: {AuthType}",
                    opaqueUserId,
                    string.Join(",", roles),
                    claimsPrincipal.Identity.AuthenticationType);

                return (opaqueUserId, roles);
            }

            log.LogInformation("Anonymous/unauthenticated request");
            return ("anonymous", Array.Empty<string>());
        }

        private static async Task<object> ProcessRequestAsync(
            string path,
            string requestBody,
            DiagnosticContext ctx,
            ILogger log)
        {
            // Example: database query with safe parameter logging
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");

            log.LogDebug(
                "Connecting to database. ConnectionString (redacted): {ConnectionString}",
                LogRedactor.RedactConnectionString(connectionString));

            var queryStartTime = DateTime.UtcNow;

            using var connection = new SqlConnection(connectionString);
            await connection.OpenAsync();

            log.LogDebug(
                "Database connection opened. Duration: {DurationMs}ms, Database: {Database}, Server: {Server}",
                (DateTime.UtcNow - queryStartTime).TotalMilliseconds,
                connection.Database,
                connection.DataSource);

            const string query = @"
                SELECT u.Id, u.DisplayName, u.AccountStatus, u.LastLoginDate
                FROM Users u
                WHERE u.Email = @Email AND u.TenantId = @TenantId";

            using var command = new SqlCommand(query, connection);

            // Parse request to get parameters
            var requestData = JsonConvert.DeserializeObject<Dictionary<string, object>>(requestBody ?? "{}");

            var emailParam = requestData?.GetValueOrDefault("email")?.ToString() ?? "";
            var tenantParam = requestData?.GetValueOrDefault("tenantId")?.ToString() ?? "";

            command.Parameters.AddWithValue("@Email", emailParam);
            command.Parameters.AddWithValue("@TenantId", tenantParam);

            // Log query with redacted parameters
            log.LogInformation(
                "Executing database query. " +
                "Query: {Query}, " +
                "Parameters: {@Parameters}, " +
                "CorrelationId: {CorrelationId}",
                query.Replace("\r\n", " ").Replace("\n", " ").Trim(),
                new
                {
                    Email = LogRedactor.MaskEmail(emailParam),
                    TenantId = tenantParam // Tenant IDs are typically safe to log
                },
                ctx.CorrelationId);

            var queryExecStart = DateTime.UtcNow;

            using var reader = await command.ExecuteReaderAsync();
            var results = new List<object>();

            while (await reader.ReadAsync())
            {
                results.Add(new
                {
                    Id = reader["Id"],
                    DisplayName = reader["DisplayName"],
                    AccountStatus = reader["AccountStatus"],
                    LastLoginDate = reader["LastLoginDate"]
                });
            }

            var queryDuration = (DateTime.UtcNow - queryExecStart).TotalMilliseconds;

            log.LogInformation(
                "Query completed. " +
                "RowCount: {RowCount}, " +
                "QueryDurationMs: {QueryDurationMs}, " +
                "CorrelationId: {CorrelationId}",
                results.Count,
                queryDuration,
                ctx.CorrelationId);

            // Warn on slow queries
            if (queryDuration > 1000)
            {
                log.LogWarning(
                    "Slow query detected. DurationMs: {DurationMs}, Query: {Query}, CorrelationId: {CorrelationId}",
                    queryDuration,
                    query,
                    ctx.CorrelationId);
            }

            return results;
        }
    }
